{
  "$schema": "https://json-schema.org/draft/2020-12/schema",
  "$id": "./candidate-change.schema.json",
  "title": "Candidate change",
  "type": "object",
  "additionalProperties": false,
  "required": [
    "schema_version",
    "record_type",
    "id",
    "name",
    "lifecycle_status",
    "submitted_at",
    "scope",
    "proposed_records",
    "required_review_lanes"
  ],
  "properties": {
    "schema_version": {
      "const": "1.0.0"
    },
    "record_type": {
      "const": "candidate_change"
    },
    "id": {
      "$ref": "./common.schema.json#/$defs/candidateChangeRef"
    },
    "name": {
      "type": "string"
    },
    "summary": {
      "type": "string"
    },
    "lifecycle_status": {
      "enum": [
        "draft",
        "submitted",
        "in_review",
        "needs_revision",
        "accepted",
        "rejected",
        "applied"
      ]
    },
    "submitted_at": {
      "$ref": "./common.schema.json#/$defs/dateTime"
    },
    "scope": {
      "type": "object",
      "additionalProperties": false,
      "required": [
        "question"
      ],
      "properties": {
        "question": {
          "type": "string"
        },
        "hallmark_ids": {
          "type": "array",
          "items": {
            "$ref": "./common.schema.json#/$defs/hallmarkRef"
          },
          "uniqueItems": true
        },
        "track_ids": {
          "type": "array",
          "items": {
            "$ref": "./common.schema.json#/$defs/trackRef"
          },
          "uniqueItems": true
        }
      }
    },
    "proposed_records": {
      "type": "array",
      "minItems": 1,
      "items": {
        "type": "object",
        "additionalProperties": false,
        "required": [
          "record_type",
          "record_id",
          "path",
          "change_type",
          "rationale"
        ],
        "properties": {
          "record_type": {
            "type": "string"
          },
          "record_id": {
            "$ref": "./common.schema.json#/$defs/identifier"
          },
          "path": {
            "type": "string"
          },
          "change_type": {
            "enum": [
              "create",
              "release_accept",
              "update",
              "delete"
            ]
          },
          "rationale": {
            "type": "string"
          }
        }
      }
    },
    "required_review_lanes": {
      "type": "array",
      "items": {
        "enum": [
          "source_fidelity",
          "extraction_fidelity",
          "taxonomy_mapping",
          "synthesis_boundary",
          "safety_limitations"
        ]
      },
      "uniqueItems": true
    },
    "evidence_review_ids": {
      "type": "array",
      "items": {
        "$ref": "./common.schema.json#/$defs/evidenceReviewRef"
      },
      "uniqueItems": true
    },
    "promotion": {
      "type": "object",
      "additionalProperties": false,
      "required": [
        "target_status",
        "promoted_at",
        "promoted_by_agent",
        "reviewed_review_ids",
        "summary"
      ],
      "properties": {
        "target_status": {
          "enum": [
            "accepted",
            "applied"
          ]
        },
        "promoted_at": {
          "$ref": "./common.schema.json#/$defs/dateTime"
        },
        "promoted_by_agent": {
          "type": "string"
        },
        "reviewed_review_ids": {
          "type": "array",
          "items": {
            "$ref": "./common.schema.json#/$defs/evidenceReviewRef"
          },
          "uniqueItems": true
        },
        "reconciliation_decision_ids": {
          "type": "array",
          "items": {
            "$ref": "./common.schema.json#/$defs/identifier"
          },
          "uniqueItems": true
        },
        "summary": {
          "type": "string"
        }
      }
    }
  }
}

{
  "$schema": "https://json-schema.org/draft/2020-12/schema",
  "$id": "./evidence-review.schema.json",
  "title": "Evidence review",
  "type": "object",
  "additionalProperties": false,
  "required": [
    "schema_version",
    "record_type",
    "id",
    "candidate_change_id",
    "review_lane",
    "reviewer_kind",
    "status",
    "verdict",
    "blocking",
    "summary",
    "findings"
  ],
  "properties": {
    "schema_version": {
      "const": "1.0.0"
    },
    "record_type": {
      "const": "evidence_review"
    },
    "id": {
      "$ref": "./common.schema.json#/$defs/evidenceReviewRef"
    },
    "candidate_change_id": {
      "$ref": "./common.schema.json#/$defs/candidateChangeRef"
    },
    "review_lane": {
      "enum": [
        "source_fidelity",
        "extraction_fidelity",
        "taxonomy_mapping",
        "synthesis_boundary",
        "safety_limitations"
      ]
    },
    "reviewer_kind": {
      "enum": [
        "agent",
        "supervisor_agent",
        "system"
      ]
    },
    "reviewer_id": {
      "type": "string"
    },
    "status": {
      "enum": [
        "draft",
        "complete",
        "superseded"
      ]
    },
    "verdict": {
      "enum": [
        "accept",
        "needs_revision",
        "reject"
      ]
    },
    "blocking": {
      "type": "boolean"
    },
    "summary": {
      "type": "string"
    },
    "findings": {
      "type": "array",
      "items": {
        "type": "object",
        "additionalProperties": false,
        "required": [
          "finding_id",
          "severity",
          "category",
          "claim_or_issue",
          "why_it_matters",
          "recommended_action",
          "resolution_status"
        ],
        "properties": {
          "finding_id": {
            "$ref": "./common.schema.json#/$defs/identifier"
          },
          "severity": {
            "enum": [
              "critical",
              "major",
              "minor",
              "note"
            ]
          },
          "category": {
            "enum": [
              "source_mismatch",
              "extraction_error",
              "endpoint_boundary",
              "interpretation_overreach",
              "missing_caveat",
              "taxonomy_mapping",
              "safety_limitation",
              "other"
            ]
          },
          "claim_or_issue": {
            "type": "string"
          },
          "why_it_matters": {
            "type": "string"
          },
          "recommended_action": {
            "type": "string"
          },
          "resolution_status": {
            "enum": [
              "open",
              "addressed",
              "closed"
            ]
          }
        }
      }
    }
  }
}

